The first verifiable production slice is a single-module boundary-and-calculation implementation: validate `unknown` exactly once at the trust boundary, convert it into a trusted local shape, then run straight-line integer arithmetic.

```ts
export type QuoteRequest = {
  customerKind: "retail" | "trade";
  subtotalCents: number;
  destination: "domestic" | "international";
  expedited?: boolean;
};

export type Quote = {
  subtotalCents: number;
  discountCents: number;
  shippingCents: number;
  totalCents: number;
};

export class QuoteInputError extends Error {
  readonly field: string;

  constructor(field: string, message = `Invalid field: ${field}`) {
    super(message);
    this.name = "QuoteInputError";
    this.field = field;
  }
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function requireEnum<T extends string>(
  obj: Record<string, unknown>,
  field: string,
  allowed: readonly T[],
): T {
  const value = obj[field];
  if (typeof value !== "string" || !allowed.includes(value as T)) {
    throw new QuoteInputError(field);
  }
  return value as T;
}

function requireNonnegativeInteger(
  obj: Record<string, unknown>,
  field: string,
): number {
  const value = obj[field];
  if (typeof value !== "number" || !Number.isInteger(value) || value < 0) {
    throw new QuoteInputError(field);
  }
  return value;
}

function requireOptionalBoolean(
  obj: Record<string, unknown>,
  field: string,
): boolean {
  const value = obj[field];
  if (value === undefined) {
    return false;
  }
  if (typeof value !== "boolean") {
    throw new QuoteInputError(field);
  }
  return value;
}

function parseQuoteRequest(input: unknown): QuoteRequest {
  if (!isRecord(input)) {
    throw new QuoteInputError("input", "Input must be an object");
  }

  return {
    customerKind: requireEnum(input, "customerKind", ["retail", "trade"]),
    subtotalCents: requireNonnegativeInteger(input, "subtotalCents"),
    destination: requireEnum(input, "destination", ["domestic", "international"]),
    expedited: requireOptionalBoolean(input, "expedited"),
  };
}

export function quoteOrder(input: unknown): Quote {
  const request = parseQuoteRequest(input);

  const discountCents =
    request.customerKind === "trade"
      ? Math.floor(request.subtotalCents * 0.1)
      : 0;

  const shippingCents =
    (request.destination === "domestic" ? 500 : 1500) +
    (request.expedited ? 700 : 0);

  const totalCents =
    request.subtotalCents - discountCents + shippingCents;

  return {
    subtotalCents: request.subtotalCents,
    discountCents,
    shippingCents,
    totalCents,
  };
}
```

Tests for the smallest useful slice:

```ts
import { describe, expect, it } from "vitest";
import { QuoteInputError, quoteOrder } from "./quoteOrder";

describe("quoteOrder", () => {
  it("quotes a retail domestic order", () => {
    expect(
      quoteOrder({
        customerKind: "retail",
        subtotalCents: 2000,
        destination: "domestic",
      }),
    ).toEqual({
      subtotalCents: 2000,
      discountCents: 0,
      shippingCents: 500,
      totalCents: 2500,
    });
  });

  it("quotes a trade international expedited order with floor discount", () => {
    expect(
      quoteOrder({
        customerKind: "trade",
        subtotalCents: 1999,
        destination: "international",
        expedited: true,
      }),
    ).toEqual({
      subtotalCents: 1999,
      discountCents: 199,
      shippingCents: 2200,
      totalCents: 4000,
    });
  });

  it("treats omitted expedited as false", () => {
    expect(
      quoteOrder({
        customerKind: "trade",
        subtotalCents: 1000,
        destination: "domestic",
      }),
    ).toEqual({
      subtotalCents: 1000,
      discountCents: 100,
      shippingCents: 500,
      totalCents: 1400,
    });
  });

  it.each([
    [null, "input"],
    [{}, "customerKind"],
    [{ customerKind: "vip", subtotalCents: 100, destination: "domestic" }, "customerKind"],
    [{ customerKind: "retail", subtotalCents: -1, destination: "domestic" }, "subtotalCents"],
    [{ customerKind: "retail", subtotalCents: 12.5, destination: "domestic" }, "subtotalCents"],
    [{ customerKind: "retail", subtotalCents: 100, destination: "mars" }, "destination"],
    [{ customerKind: "retail", subtotalCents: 100, destination: "domestic", expedited: "yes" }, "expedited"],
  ])("rejects malformed input %#", (input, field) => {
    try {
      quoteOrder(input);
      throw new Error("expected QuoteInputError");
    } catch (error) {
      expect(error).toBeInstanceOf(QuoteInputError);
      expect((error as QuoteInputError).field).toBe(field);
    }
  });
});
```

Construction decisions:

- Input validation: `input` is hostile because it came from JSON. Parse once at the boundary and never mix validation checks into pricing logic.
- Data meaning: `subtotalCents` is not just a `number`; it is a nonnegative whole-cent amount, so integer and range checks belong in validation.
- Arithmetic: keep all values in cents and use integer-only results. `Math.floor(subtotalCents * 0.1)` matches the required trade discount rounding rule.
- Control shape: one parse step plus one straight-line compute step is the smallest shape that is easy to inspect and test.
- Error semantics: `QuoteInputError` includes `field` so the HTTP layer can deterministically map failures to a 400 response and a field-specific message.
- Smallest verifiable increment: cover one retail case, one trade+expedited case, omitted `expedited`, and one invalid case per field. That exercises every required rule without pulling in HTTP or persistence concerns.

